// contextKey is a custom type for context keys to avoid collisions.
type contextKey string

const (
	UserContextKey contextKey = "user"
)

// UserClaims represents the custom claims embedded in the JWT.
type UserClaims struct {
	UserID   string `json:"user_id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Role     string `json:"role"`
	jwt.RegisteredClaims
}

// UserInfo holds user information extracted from the JWT and stored in context.
type UserInfo struct {
	UserID   string
	Username string
	Email    string
	Role     string
	Subject  string
	Issuer   string
}

// JWTMiddlewareConfig holds configuration for the JWT middleware.
type JWTMiddlewareConfig struct {
	SecretKey        []byte
	Issuer           string
	Audience         string
	AllowedAlgorithms []string
}

// NewJWTMiddleware creates a new JWT verification middleware with the given config.
func NewJWTMiddleware(config JWTMiddlewareConfig) func(http.Handler) http.Handler {
	if len(config.AllowedAlgorithms) == 0 {
		config.AllowedAlgorithms = []string{"HS256"}
	}

	allowedAlgMap := make(map[string]bool)
	for _, alg := range config.AllowedAlgorithms {
		allowedAlgMap[alg] = true
	}

	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Extract token from Authorization header
			authHeader := r.Header.Get("Authorization")
			if authHeader == "" {
				http.Error(w, `{"error": "missing Authorization header"}`, http.StatusUnauthorized)
				return
			}

			parts := strings.SplitN(authHeader, " ", 2)
			if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
				http.Error(w, `{"error": "invalid Authorization header format, expected 'Bearer <token>'"}`, http.StatusUnauthorized)
				return
			}

			tokenString := strings.TrimSpace(parts[1])
			if tokenString == "" {
				http.Error(w, `{"error": "empty token"}`, http.StatusUnauthorized)
				return
			}

			// Parse and validate the token
			claims := &UserClaims{}

			parserOptions := []jwt.ParserOption{
				jwt.WithValidMethods(config.AllowedAlgorithms),
				jwt.WithExpirationRequired(),
				jwt.WithIssuedAt(),
			}

			if config.Issuer != "" {
				parserOptions = append(parserOptions, jwt.WithIssuer(config.Issuer))
			}

			if config.Audience != "" {
				parserOptions = append(parserOptions, jwt.WithAudience(config.Audience))
			}

			token, err := jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (interface{}, error) {
				// Explicit algorithm allowlisting check
				alg := token.Method.Alg()
				if !allowedAlgMap[alg] {
					return nil, fmt.Errorf("unexpected signing method: %s", alg)
				}
				return config.SecretKey, nil
			}, parserOptions...)

			if err != nil {
				log.Printf("JWT validation error: %v", err)
				http.Error(w, fmt.Sprintf(`{"error": "invalid token: %s"}`, err.Error()), http.StatusUnauthorized)
				return
			}

			if !token.Valid {
				http.Error(w, `{"error": "invalid token"}`, http.StatusUnauthorized)
				return
			}

			// Validate required custom claims
			if claims.UserID == "" {
				http.Error(w, `{"error": "token missing required user_id claim"}`, http.StatusUnauthorized)
				return
			}

			// Build user info and set in context
			userInfo := &UserInfo{
				UserID:   claims.UserID,
				Username: claims.Username,
				Email:    claims.Email,
				Role:     claims.Role,
				Subject:  claims.Subject,
				Issuer:   claims.Issuer,
			}

			ctx := context.WithValue(r.Context(), UserContextKey, userInfo)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// GetUserFromContext extracts user information from the request context.
func GetUserFromContext(ctx context.Context) (*UserInfo, bool) {
	user, ok := ctx.Value(UserContextKey).(*UserInfo)
	return user, ok
}

// GenerateToken creates a JWT token for testing/demonstration purposes.
func GenerateToken(secretKey []byte, userID, username, email, role, issuer, audience string, duration time.Duration) (string, error) {
	now := time.Now()
	claims := UserClaims{
		UserID:   userID,
		Username: username,
		Email:    email,
		Role:     role,
		RegisteredClaims: jwt.RegisteredClaims{
			Issuer:    issuer,
			Subject:   userID,
			Audience:  jwt.ClaimStrings{audience},
			ExpiresAt: jwt.NewNumericDate(now.Add(duration)),
			IssuedAt:  jwt.NewNumericDate(now),
			NotBefore: jwt.NewNumericDate(now),
			ID:        fmt.Sprintf("%d", now.UnixNano()),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(secretKey)
}

// Example protected handler
func protectedHandler(w http.ResponseWriter, r *http.Request) {
	user, ok := GetUserFromContext(r.Context())
	if !ok {
		http.Error(w, `{"error": "user not found in context"}`, http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	fmt.Fprintf(w, `{"message": "Hello, %s!", "user_id": "%s", "email": "%s", "role": "%s"}`,
		user.Username, user.UserID, user.Email, user.Role)
}

// Public handler that doesn't require authentication
func publicHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	fmt.Fprint(w, `{"message": "This is a public endpoint"}`)
}

